-- Tạo partitioned table
CREATE TABLE audit_logs (
    id BIGSERIAL,
    event_type TEXT NOT NULL,
    user_id INT,
    payload JSONB,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
) PARTITION BY RANGE (created_at);

-- Tạo partitions
CREATE TABLE audit_logs_2026_01 PARTITION OF audit_logs
    FOR VALUES FROM ('2026-01-01') TO ('2026-02-01');

CREATE TABLE audit_logs_2026_06 PARTITION OF audit_logs
    FOR VALUES FROM ('2026-06-01') TO ('2026-07-01');

-- Default partition cho data không match
CREATE TABLE audit_logs_default PARTITION OF audit_logs DEFAULT;

-- Tạo index trên parent → tự động tạo trên tất cả partitions
CREATE INDEX idx_audit_user ON audit_logs (user_id, created_at);

-- Query tự động partition pruning
EXPLAIN SELECT * FROM audit_logs
WHERE created_at > '2026-06-01'; -- chỉ scan audit_logs_2026_06!

-- Archive: detach old partition
ALTER TABLE audit_logs DETACH PARTITION audit_logs_2026_01;
-- Giờ audit_logs_2026_01 là table bình thường, archive sang cold storage

-- Attach prebuilt partition (bulk insert nhanh)
CREATE TABLE audit_logs_2026_07 (LIKE audit_logs INCLUDING ALL);
-- ... bulk load data ...
ALTER TABLE audit_logs ATTACH PARTITION audit_logs_2026_07
    FOR VALUES FROM ('2026-07-01') TO ('2026-08-01');

-- Hash partitioning cho multi-tenant
CREATE TABLE events PARTITION BY HASH (tenant_id);
CREATE TABLE events_0 PARTITION OF events FOR VALUES WITH (MODULUS 4, REMAINDER 0);
